// Some portions generated by Codex
package org.eclipse.rdf4j.sail.lmdb;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertFalse;
import static org.junit.jupiter.api.Assertions.assertTrue;

import java.util.List;

import org.eclipse.rdf4j.model.base.CoreDatatype;
import org.eclipse.rdf4j.model.impl.SimpleValueFactory;
import org.eclipse.rdf4j.model.vocabulary.XSD;
import org.junit.jupiter.api.Test;

class RdfTermDomainClassificationTest {

	private static final SimpleValueFactory VF = SimpleValueFactory.getInstance();

	@Test
	void classifiesCanonicalIntegerLiteralsAsOverlappingFacts() {
		RdfTermDomain zero = RdfTermDomain.classify(VF.createLiteral("0", XSD.INTEGER));
		assertHas(zero, RdfTermDomain.Fact.LITERAL);
		assertHas(zero, RdfTermDomain.Fact.LITERAL_WITHOUT_LANGUAGE);
		assertHas(zero, RdfTermDomain.Fact.NUMBER);
		assertHas(zero, RdfTermDomain.Fact.CANONICAL_INTEGER);
		assertHasDatatype(zero, CoreDatatype.XSD.INTEGER);

		assertHas(RdfTermDomain.classify(VF.createLiteral("7", XSD.INT)),
				RdfTermDomain.Fact.CANONICAL_INTEGER);
		assertHas(RdfTermDomain.classify(VF.createLiteral("-7", XSD.INTEGER)),
				RdfTermDomain.Fact.CANONICAL_INTEGER);
	}

	@Test
	void classifiesValidNonCanonicalIntegerAndNonIntegerNumericLiteralsAsNumber() {
		RdfTermDomain leadingZero = RdfTermDomain.classify(VF.createLiteral("007", XSD.INT));
		assertHas(leadingZero, RdfTermDomain.Fact.NUMBER);
		assertFalse(leadingZero.has(RdfTermDomain.Fact.CANONICAL_INTEGER));
		assertHasDatatype(leadingZero, CoreDatatype.XSD.INT);

		RdfTermDomain positive = RdfTermDomain.classify(VF.createLiteral("+7", XSD.INTEGER));
		assertHas(positive, RdfTermDomain.Fact.NUMBER);
		assertFalse(positive.has(RdfTermDomain.Fact.CANONICAL_INTEGER));
		assertHasDatatype(positive, CoreDatatype.XSD.INTEGER);

		RdfTermDomain decimal = RdfTermDomain.classify(VF.createLiteral("1.0", XSD.DECIMAL));
		assertHas(decimal, RdfTermDomain.Fact.NUMBER);
		assertFalse(decimal.has(RdfTermDomain.Fact.CANONICAL_INTEGER));
		assertHasDatatype(decimal, CoreDatatype.XSD.DECIMAL);

		RdfTermDomain doubleValue = RdfTermDomain.classify(VF.createLiteral("1.0E0", XSD.DOUBLE));
		assertHas(doubleValue, RdfTermDomain.Fact.NUMBER);
		assertFalse(doubleValue.has(RdfTermDomain.Fact.CANONICAL_INTEGER));
		assertHasDatatype(doubleValue, CoreDatatype.XSD.DOUBLE);
	}

	@Test
	void classifiesInvalidNumericAndNonNumericValuesWithoutNumericFacts() {
		RdfTermDomain invalidInt = RdfTermDomain
				.classify(VF.createLiteral("not-an-int", XSD.INT));
		assertHas(invalidInt, RdfTermDomain.Fact.LITERAL);
		assertHasDatatype(invalidInt, CoreDatatype.XSD.INT);
		assertFalse(invalidInt.has(RdfTermDomain.Fact.NUMBER));
		assertFalse(invalidInt.has(RdfTermDomain.Fact.CANONICAL_INTEGER));

		RdfTermDomain plain = RdfTermDomain.classify(VF.createLiteral("plain"));
		assertHas(plain, RdfTermDomain.Fact.LITERAL);
		assertHas(plain, RdfTermDomain.Fact.LITERAL_WITHOUT_LANGUAGE);
		assertHasDatatype(plain, CoreDatatype.XSD.STRING);
		assertFalse(plain.has(RdfTermDomain.Fact.NUMBER));
	}

	@Test
	void classifiesResourceAndLanguageFacts() {
		RdfTermDomain iri = RdfTermDomain.classify(VF.createIRI("http://example.com/value"));
		assertHas(iri, RdfTermDomain.Fact.IRI);
		assertFalse(iri.has(RdfTermDomain.Fact.LITERAL));

		RdfTermDomain bnode = RdfTermDomain.classify(VF.createBNode());
		assertHas(bnode, RdfTermDomain.Fact.BNODE);
		assertFalse(bnode.has(RdfTermDomain.Fact.IRI));

		RdfTermDomain langLiteral = RdfTermDomain.classify(VF.createLiteral("text", "en"));
		assertHas(langLiteral, RdfTermDomain.Fact.LITERAL);
		assertHas(langLiteral, RdfTermDomain.Fact.LITERAL_WITH_LANGUAGE);
		assertFalse(langLiteral.has(RdfTermDomain.Fact.LITERAL_WITHOUT_LANGUAGE));
	}

	@Test
	void classifiesDateTimezoneFacts() {
		RdfTermDomain utc = RdfTermDomain.classify(VF.createLiteral("2024-01-01Z", XSD.DATE));
		assertHas(utc, RdfTermDomain.Fact.DATE_UTC);
		assertFalse(utc.has(RdfTermDomain.Fact.DATE_WITHOUT_TIMEZONE));
		assertHasDatatype(utc, CoreDatatype.XSD.DATE);

		RdfTermDomain withoutTimezone = RdfTermDomain
				.classify(VF.createLiteral("2024-01-01", XSD.DATE));
		assertHas(withoutTimezone, RdfTermDomain.Fact.DATE_WITHOUT_TIMEZONE);
		assertFalse(withoutTimezone.has(RdfTermDomain.Fact.DATE_UTC));
		assertHasDatatype(withoutTimezone, CoreDatatype.XSD.DATE);
	}

	@Test
	void classifiesCanonicalDateTimeFacts() {
		RdfTermDomain canonicalUtc = RdfTermDomain
				.classify(VF.createLiteral("2024-01-01T05:00:00Z", XSD.DATETIME));
		assertHas(canonicalUtc, RdfTermDomain.Fact.CANONICAL_DATETIME);

		RdfTermDomain canonicalWithoutTimezone = RdfTermDomain
				.classify(VF.createLiteral("2024-01-01T05:00:00", XSD.DATETIME));
		assertHas(canonicalWithoutTimezone, RdfTermDomain.Fact.CANONICAL_DATETIME);

		RdfTermDomain trailingFractionalZeros = RdfTermDomain
				.classify(VF.createLiteral("2024-01-01T05:00:00.000Z", XSD.DATETIME));
		assertFalse(trailingFractionalZeros.has(RdfTermDomain.Fact.CANONICAL_DATETIME));

		RdfTermDomain utcOffset = RdfTermDomain
				.classify(VF.createLiteral("2024-01-01T05:00:00+00:00", XSD.DATETIME));
		assertFalse(utcOffset.has(RdfTermDomain.Fact.CANONICAL_DATETIME));

		RdfTermDomain fractionalSeconds = RdfTermDomain
				.classify(VF.createLiteral("2024-01-01T05:00:00.5Z", XSD.DATETIME));
		assertHas(fractionalSeconds, RdfTermDomain.Fact.CANONICAL_DATETIME);

		// Other calendar datatypes have no canonicalizer, so no canonicity can be claimed for them.
		RdfTermDomain date = RdfTermDomain.classify(VF.createLiteral("2024-01-01Z", XSD.DATE));
		assertFalse(date.has(RdfTermDomain.Fact.CANONICAL_DATETIME));
	}

	@Test
	void observedJoinsDropCanonicalDateTimeWhenAnyStoredFormIsNotCanonical() {
		RdfTermDomain canonical = RdfTermDomain
				.classify(VF.createLiteral("2024-01-01T05:00:00Z", XSD.DATETIME));
		RdfTermDomain nonCanonical = RdfTermDomain
				.classify(VF.createLiteral("2024-01-01T05:00:00.000Z", XSD.DATETIME));
		RdfTermDomain mixed = canonical.combine(nonCanonical);
		assertHas(mixed, RdfTermDomain.Fact.DATE_UTC);
		assertFalse(mixed.has(RdfTermDomain.Fact.CANONICAL_DATETIME));

		RdfTermDomain allCanonical = canonical
				.combine(RdfTermDomain.classify(VF.createLiteral("2025-06-30T12:30:45Z", XSD.DATETIME)));
		assertHas(allCanonical, RdfTermDomain.Fact.CANONICAL_DATETIME);
	}

	@Test
	void classifiesEveryXsdDatatypeFact() {
		for (CoreDatatype.XSD datatype : CoreDatatype.XSD.values()) {
			RdfTermDomain guarantee = RdfTermDomain
					.classify(VF.createLiteral("value", datatype.getIri()));
			assertHasDatatype(guarantee, datatype);
		}
	}

	@Test
	void observedJoinsKeepPossibleFactsAndSharedUniversalFacts() {
		RdfTermDomain canonicalInt = RdfTermDomain.classify(VF.createLiteral("7", XSD.INT));
		RdfTermDomain decimal = RdfTermDomain.classify(VF.createLiteral("7.0", XSD.DECIMAL));
		RdfTermDomain mixedNumeric = canonicalInt.combine(decimal);
		assertHas(mixedNumeric, RdfTermDomain.Fact.LITERAL);
		assertHas(mixedNumeric, RdfTermDomain.Fact.LITERAL_WITHOUT_LANGUAGE);
		assertHas(mixedNumeric, RdfTermDomain.Fact.NUMBER);
		assertFalse(mixedNumeric.has(RdfTermDomain.Fact.CANONICAL_INTEGER));
		assertHasDatatype(mixedNumeric, CoreDatatype.XSD.INT);
		assertHasDatatype(mixedNumeric, CoreDatatype.XSD.DECIMAL);

		RdfTermDomain mixedValueKinds = canonicalInt
				.combine(RdfTermDomain.classify(VF.createIRI("http://example.com/value")));
		assertHas(mixedValueKinds, RdfTermDomain.Fact.LITERAL);
		assertHas(mixedValueKinds, RdfTermDomain.Fact.IRI);
		assertFalse(mixedValueKinds.has(RdfTermDomain.Fact.NUMBER));
	}

	@Test
	void observedResourceJoinKeepsPossibleResourceKinds() {
		RdfTermDomain iri = RdfTermDomain.classify(VF.createIRI("http://example.com/value"));
		RdfTermDomain bnode = RdfTermDomain.classify(VF.createBNode());

		RdfTermDomain resource = iri.combine(bnode);

		assertHas(resource, RdfTermDomain.Fact.IRI);
		assertHas(resource, RdfTermDomain.Fact.BNODE);
		assertFalse(resource.has(RdfTermDomain.Fact.LITERAL));
		assertEquals(null, resource.singleValueKind());
	}

	@Test
	void queryMeetDetectsKindDatatypeAndTimezoneContradictions() {
		RdfTermDomain iri = RdfTermDomain.classify(VF.createIRI("http://example.com/value"));
		RdfTermDomain literal = RdfTermDomain.classify(VF.createLiteral("value"));
		assertTrue(iri.meetRequired(literal).isEmpty());

		RdfTermDomain intLiteral = RdfTermDomain.classify(VF.createLiteral("7", XSD.INT));
		RdfTermDomain decimalLiteral = RdfTermDomain
				.classify(VF.createLiteral("7.0", XSD.DECIMAL));
		assertTrue(intLiteral.meetRequired(decimalLiteral).isEmpty());

		RdfTermDomain utcDate = RdfTermDomain.classify(VF.createLiteral("2024-01-01Z", XSD.DATE));
		RdfTermDomain localDate = RdfTermDomain
				.classify(VF.createLiteral("2024-01-01", XSD.DATE));
		assertTrue(utcDate.meetRequired(localDate).isEmpty());
	}

	@Test
	void unknownAndKnownUnrestrictedDoNotForceContradictions() {
		RdfTermDomain literal = RdfTermDomain.classify(VF.createLiteral("value"));

		assertEquals(literal, RdfTermDomain.UNKNOWN.meetRequired(literal));
		assertEquals(literal, RdfTermDomain.UNRESTRICTED.meetRequired(literal));
		assertFalse(RdfTermDomain.UNKNOWN.meetRequired(RdfTermDomain.IRI).isEmpty());
		assertFalse(RdfTermDomain.UNRESTRICTED.meetRequired(RdfTermDomain.BNODE).isEmpty());
	}

	@Test
	void queryMeetNarrowsMixedKindDomainWithoutTreatingLiteralFactsAsIriContradictions() {
		RdfTermDomain iri = RdfTermDomain.classify(VF.createIRI("http://example.com/value"));
		RdfTermDomain integerLiteral = RdfTermDomain.classify(VF.createLiteral("7", XSD.INT));
		RdfTermDomain mixed = iri.joinObserved(integerLiteral);

		RdfTermDomain narrowed = mixed.meetRequired(RdfTermDomain.IRI);

		assertEquals(RdfTermDomain.ValueKind.IRI, narrowed.singleValueKind());
		assertFalse(narrowed.hasDatatype(CoreDatatype.XSD.INT));
	}

	@Test
	void finiteValuesMeetFiltersExactValuesByDomainFacts() {
		var canonical = VF.createLiteral("7", XSD.INT);
		var nonCanonical = VF.createLiteral("007", XSD.INT);
		var iri = VF.createIRI("http://example.com/value");
		RdfTermDomain finite = RdfTermDomain
				.finiteValues(List.of(canonical, nonCanonical, iri));

		RdfTermDomain literals = finite.meetRequired(RdfTermDomain.LITERAL);
		assertTrue(literals.finiteValues().contains(canonical));
		assertTrue(literals.finiteValues().contains(nonCanonical));
		assertFalse(literals.finiteValues().contains(iri));

		RdfTermDomain canonicalOnly = finite.meetRequired(RdfTermDomain.CANONICAL_INTEGER);
		assertEquals(1, canonicalOnly.finiteValues().size());
		assertTrue(canonicalOnly.finiteValues().contains(canonical));
	}

	private static void assertHas(RdfTermDomain guarantee, RdfTermDomain.Fact fact) {
		assertTrue(guarantee.has(fact), () -> "Expected " + guarantee + " to contain " + fact);
	}

	private static void assertHasDatatype(RdfTermDomain guarantee, CoreDatatype.XSD datatype) {
		assertTrue(guarantee.hasDatatype(datatype), () -> "Expected " + guarantee + " to contain " + datatype);
	}
}
